window.SmartRisk=window.SmartRisk||{};SmartRisk.Chart={line(data){const w=720,h=260,p=34,m=Math.max(...data.map(i=>i.value),100),sx=(w-p*2)/Math.max(data.length-1,1),pts=data.map((i,n)=>({...i,x:p+n*sx,y:h-p-(i.value/m)*(h-p*2)})),line=pts.map(x=>`${x.x},${x.y}`).join(" "),area=`${p},${h-p} ${line} ${w-p},${h-p}`;return `<div class="chart-wrap"><svg class="chart-svg" viewBox="0 0 ${w} ${h}">${[.25,.5,.75,1].map(v=>{const y=h-p-v*(h-p*2);return `<line class="chart-grid-line" x1="${p}" y1="${y}" x2="${w-p}" y2="${y}"/>`}).join("")}<polygon class="chart-area" points="${area}"></polygon><polyline class="chart-line" points="${line}"></polyline>${pts.map(x=>`<circle class="chart-point" cx="${x.x}" cy="${x.y}" r="5"></circle><text class="chart-label" x="${x.x}" y="${h-8}" text-anchor="middle">${x.label}</text>`).join("")}</svg></div>`}};